		<li><strong><?php esc_html_e( 'El Derecho de Rectificación:', 'alvobot-pro' ); ?></strong> <?php esc_html_e( 'Tiene el derecho de solicitar la corrección de información inexacta, incompleta o desactualizada.', 'alvobot-pro' ); ?></li>
