		<li><strong><?php esc_html_e( 'El Derecho a Retirar el Consentimiento:', 'alvobot-pro' ); ?></strong> <?php esc_html_e( 'Cuando el tratamiento de datos se basa en su consentimiento, tiene el derecho de retirarlo en cualquier momento, sin afectar la legalidad del tratamiento anterior.', 'alvobot-pro' ); ?></li>
